// Cache etkisini gözlemleme
const size = 10000000;
const arr = new Array(size);

// Cache-friendly: Sequential access
console.time('Sequential');
for (let i = 0; i < size; i++) {
    arr[i] = i * 2;
}
console.timeEnd('Sequential');

// Cache-unfriendly: Random access
console.time('Random');
for (let i = 0; i < size; i++) {
    const index = Math.floor(Math.random() * size);
    arr[index] = index * 2;
}
console.timeEnd('Random');

// Matrix multiplication - cache optimization
function matrixMultiply(A, B, N) {
    const C = Array(N).fill(0).map(() => Array(N).fill(0));

    // Cache-friendly: i-k-j order
    for (let i = 0; i < N; i++) {
        for (let k = 0; k < N; k++) {
            for (let j = 0; j < N; j++) {
                C[i][j] += A[i][k] * B[k][j];
            }
        }
    }
    return C;
}

